const express = require('express');
const app = express();

app.use(express.json());

const levels = {
  1: { reward: 'coins' },
  2: { reward: 'gems' },
  3: { reward: 'hearts' }
};

app.post('/complete-level', (req, res) => {
  const { level, score, time } = req.body;

  if (!levels[level]) {
    return res.status(400).json({ message: 'Invalid level' });
  }

  const reward = levels[level].reward;

  res.json({ reward });
});

app.post('/claim-reward', (req, res) => {
  const { reward } = req.body;

  if (!levels[reward]) {
    return res.status(400).json({ message: 'Invalid reward' });
  }

  // Logic to award the reward to the user goes here
  // ...

  res.json({ message: 'Reward claimed' });
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});